12	interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	interface QuoteResult {
17	  premium: number;
18	}
19	
20	const COMPONENT_BLOCK_SIZE = 3;
21	const COMPONENT_BLOCK_PRICE = 60;
22	
23	interface Item {
24	  type: string;
25	  enchantment?: number;
26	  cursed?: boolean;
27	}
28	
29	const CURSED_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
32	
33	const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
34	
35	const quotePremium = (items: Array<Item>): number => {
36	  const typeCounts: Record<string, number> = {};
37	  for (const item of items) {
38	    typeCounts[item.type] = (typeCounts[item.type] ?? 0) + 1;
39	  }
40	  let total = 0;
41	  for (const [type, count] of Object.entries(typeCounts)) {
42	    if (count === COMPONENT_BLOCK_SIZE) {
43	      total += COMPONENT_BLOCK_PRICE;
44	    } else {
45	      total += count * basePremiumFor(type);
46	    }
47	  }
48	  for (const item of items) {
49	    if (item.cursed) {
50	      total += basePremiumFor(item.type) * CURSED_SURCHARGE_RATE;
51	    }
52	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
53	      total += basePremiumFor(item.type) * HIGH_ENCHANTMENT_SURCHARGE_RATE;
54	    }
55	  }
56	  return total + PROCESSING_FEE;
57	};
58	
59	export const processSteps = (customer: Customer, steps: Array<{ op: string; items: Array<Item> }>): Array<QuoteResult> =>
60	  steps.map((step) => ({
61	    premium: quotePremium(step.items),
62	  }));
